import React, { useState } from 'react'; // Importando useState para gerenciar o estado do dropdown
import { Link } from 'react-router-dom'; // Importando o Link para navegação entre as rotas
import './Navbar.css'; // Importando o arquivo de estilos CSS

const Navbar = () => {
  // Estado para controlar qual dropdown está aberto
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [searchQuery, setSearchQuery] = useState(''); // Estado para o campo de busca

  // Função para abrir o dropdown
  const toggleDropdown = (dropdownName) => {
    if (activeDropdown === dropdownName) {
      setActiveDropdown(null); // Fecha o dropdown se for o mesmo
    } else {
      setActiveDropdown(dropdownName); // Abre o dropdown selecionado
    }
  };

  // Função para lidar com a busca
  const handleSearch = () => {
    console.log('Buscando:', searchQuery);
    // Implementar a lógica de busca, como redirecionar para uma página de resultados
  };

  // Função para fechar o dropdown ao clicar em um link
  const handleLinkClick = () => {
    setActiveDropdown(null); // Fecha o dropdown ao clicar em um link
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="navbar-logo">Prometheus</div>
        <ul className="navbar-links">
          {/* Gestão Dropdown */}
          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('gestao')}>Gestão</Link>
            {activeDropdown === 'gestao' && (
              <ul className="dropdown-menu">
                <li><Link to="/g_atendimentos.html" onClick={handleLinkClick}>Atendimentos</Link></li>
                <li><Link to="/gestao/item2" onClick={handleLinkClick}>Pessoa</Link></li>
                <li><Link to="/gestao/item3" onClick={handleLinkClick}>Workflow</Link></li>
                <li><Link to="/gestao/item4" onClick={handleLinkClick}>Timesheet</Link></li>
                <li><Link to="/gestao/item5" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>

          {/* Atendimentos Dropdown */}
          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('atendimentos')}>Atendimentos</Link>
            {activeDropdown === 'atendimentos' && (
              <ul className="dropdown-menu">
                <li><Link to="/atendimentos/item1" onClick={handleLinkClick}>Lista de Atendimentos</Link></li>
                <li><Link to="/atendimentos/item2" onClick={handleLinkClick}>Histórico</Link></li>
                <li><Link to="/atendimentos/item3" onClick={handleLinkClick}>Novo Atendimento</Link></li>
                <li><Link to="/atendimentos/item4" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>

          {/* Adicionando outros dropdowns */}
          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('atividades')}>Atividades</Link>
            {activeDropdown === 'atividades' && (
              <ul className="dropdown-menu">
                <li><Link to="/atividades/item1" onClick={handleLinkClick}>Lista de Atividades</Link></li>
                <li><Link to="/atividades/item2" onClick={handleLinkClick}>Painel de Tarefas</Link></li>
                <li><Link to="/atividades/item3" onClick={handleLinkClick}>Kanban de Tarefas</Link></li>
                <li><Link to="/atividades/item4" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>

          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('processos')}>Processos</Link>
            {activeDropdown === 'processos' && (
              <ul className="dropdown-menu">
                <li><Link to="/processos/item1" onClick={handleLinkClick}>Processos</Link></li>
                <li><Link to="/processos/item2" onClick={handleLinkClick}>Intimações</Link></li>
                <li><Link to="/processos/item3" onClick={handleLinkClick}>Central de Captura</Link></li>
                <li><Link to="/processos/item4" onClick={handleLinkClick}>Andamentos Processuais</Link></li>
                <li><Link to="/processos/item5" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>

          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('financeiro')}>Financeiro</Link>
            {activeDropdown === 'financeiro' && (
              <ul className="dropdown-menu">
                <li><Link to="/financeiro/item1" onClick={handleLinkClick}>Receitas e Despesas</Link></li>
                <li><Link to="/financeiro/item2" onClick={handleLinkClick}>Extrato de Conta</Link></li>
                <li><Link to="/financeiro/item3" onClick={handleLinkClick}>Solicitações</Link></li>
                <li><Link to="/financeiro/item4" onClick={handleLinkClick}>Integração de Receitas</Link></li>
                <li><Link to="/financeiro/item5" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>

          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('documentos')}>Documentos</Link>
            {activeDropdown === 'documentos' && (
              <ul className="dropdown-menu">
                <li><Link to="/documentos/item1" onClick={handleLinkClick}>Documentos</Link></li>
                <li><Link to="/documentos/item2" onClick={handleLinkClick}>Modelos de Documentos</Link></li>
              </ul>
            )}
          </li>

          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('extensoes')}>Extensões</Link>
            {activeDropdown === 'extensoes' && (
              <ul className="dropdown-menu">
                <li><Link to="/extensoes/item1" onClick={handleLinkClick}>Conexões</Link></li>
                <li><Link to="/extensoes/item2" onClick={handleLinkClick}>Relatórios</Link></li>
              </ul>
            )}
          </li>
        </ul>
      </div>

      <div className="navbar-right">
        <div className="navbar-search">
          <input
            type="text"
            placeholder="Pesquise..."
            value={searchQuery} // Vinculando o estado ao input
            onChange={(e) => setSearchQuery(e.target.value)} // Atualizando o estado ao digitar
          />
          <button onClick={handleSearch}>Buscar</button> {/* Botão de busca */}
        </div>

        <div className="navbar-icons">
          {/* Notificações */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('notificacoes')}>🔔</button>
            {activeDropdown === 'notificacoes' && (
              <ul className="dropdown-menu">
                <li><Link to="/notificacao/item1" onClick={handleLinkClick}>Notificação 1</Link></li>
                <li><Link to="/notificacao/item2" onClick={handleLinkClick}>Notificação 2</Link></li>
                <li><Link to="/notificacao/item3" onClick={handleLinkClick}>Notificação 3</Link></li>
                <li><Link to="/notificacao/item4" onClick={handleLinkClick}>Notificação 4</Link></li>
              </ul>
            )}
          </div>

          {/* Configurações */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('configuracoes')}>⚙️</button>
            {activeDropdown === 'configuracoes' && (
              <ul className="dropdown-menu">
                <li><Link to="/configuracoes/item1" onClick={handleLinkClick}>Perfil</Link></li>
                <li><Link to="/configuracoes/item2" onClick={handleLinkClick}>Preferências</Link></li>
                <li><Link to="/configuracoes/item3" onClick={handleLinkClick}>Sair</Link></li>
              </ul>
            )}
          </div>

          {/* Ajuda */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('ajuda')}>❓</button>
            {activeDropdown === 'ajuda' && (
              <ul className="dropdown-menu">
                <li><Link to="/ajuda/item1" onClick={handleLinkClick}>FAQ</Link></li>
                <li><Link to="/ajuda/item2" onClick={handleLinkClick}>Suporte</Link></li>
              </ul>
            )}
          </div>
        </div>

        {/* Área do Usuário */}
        <div className="user-area">
          <Link to="/usuario/perfil" onClick={handleLinkClick}>Meu Perfil</Link> {/* Link para o perfil do usuário */}
          <Link to="/usuario/configuracoes" onClick={handleLinkClick}>Configurações</Link> {/* Link para configurações do usuário */}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
